var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"악인이란 무엇인가?","JPN":"悪人とは何か。","ENG":"What is a sinner?","TWN":"什麼是惡人？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 배워온 정의에 따르면, 죄를 거리낌 없이 행하는 것이 바로 악인이다.","JPN":"我々が教わってきた定義によると、何の躊躇いもなく罪を犯す者を指す。","ENG":"We were taught that sinners were ones who sin without hesitation.","TWN":"根據我們所學到的定義，肆無忌憚地犯罪的人就是惡人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 때로는, 대의라는 명목이 우리가 아는 죄의 의미를 혼란스럽게 한다.","JPN":"だが時には、大儀という名分が我々の知る罪の意味を混乱させる。","ENG":"However, our definition of sin is muddled when it is done under the pretext of a greater cause.","TWN":"但有時，大義的名義會混淆我們對於罪的定義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"죄를 행한 악인을 악인으로서 규명 짓지 못하게 한다.","JPN":"罪を犯した悪人を、悪人として糾明することを妨げる。","ENG":"It bars us from branding those who have sinned as sinners.","TWN":"我們無法將犯下罪過的惡人定義為惡人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"희생이란 이름의 눈부신 허울이 그 끔찍한 핏빛을 바래게 한다.","JPN":"犠牲という名の眩いうわべが、その残酷な血の色を色あせるようにする。","ENG":"The brilliant facade called sacrifice is enough to desaturate the crimson red from one's bloodied hands.","TWN":"名為犧牲的冠冕堂皇的外衣會暗淡那可怕的血光。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"대의를 교리로 삼은 세상에서 우리는 무슨 수로 죄를 규명하고 악인을 변별하는가…?","JPN":"大儀を教理とした世界で、我々はどうやって罪を糾明し、悪人を弁別するか……？","ENG":"In a world that views the greater cause as its doctrine, how are we to scrutinize sin and distinguish sinners...?","TWN":"在這個將大義作為教義的世界裡，我們該如何辨別罪惡、分辨惡人……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면…","JPN":"もしかしたら……","ENG":"Perhaps...","TWN":"也許……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"세상의 종말이 예견된 순간부터, 답은 정해져 있었던 걸도 모른다.","JPN":"世界の終末が予見された瞬間から、答えは決められていたのかも知れない。","ENG":"The answer was determined from the moment the end was foreseen.","TWN":"在遇見世界末日的那一刻起，答案便已揭曉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"위대한 정적이시여. 종막으로 향하는 태양문이 열렸습니다.","JPN":"偉大なる静寂よ。終幕への太陽の門が開かれました。","ENG":"O, Great Silence. The Solar Gates to the denouement have opened.","TWN":"偉大的寂靜，通往末世的太陽門已經開啟。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕이란 이름의 불협화음이 제거된 뒤엔, 저희의 세계도 다시금 평화를 되찾겠죠.","JPN":"魔王という名の不協和音が排除された暁には、私たちの世界もまた平和を取り戻すでしょう。","ENG":"After removing the dissonance called Demon Lord, peace shall once again be restored to our world.","TWN":"排除名為不和諧音的魔王之後，我們的世界將再次恢復和平。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Indeed.","TWN":"是的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"허나 세계를 지탱해야 할 뿌리가 썩어버린 이상 새로운 위협은 계속해서 눈을 뜨겠지.","JPN":"だが、世界を支えるべきの根が腐ってしまった以上、新しい脅威は続々と目覚めるであろう。","ENG":"However, the roots that sustain this very world have rotted, and new threats will continue to emerge.","TWN":"但是，支撐世界的根基已經腐朽，新的威脅會不斷甦醒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕을 토벌해 종말로부터 잠시나마 유예를 얻는 것. 그것으로 이번 원정의 목적은 충분히 달성하는 셈입니다.","JPN":"魔王を討伐し、少しでも終末までの猶予を得ること。それでこの遠征の目的は十分達成するわけです。","ENG":"Vanquishing the Demon Lord and delaying the end will be more than enough progress for this expedition.","TWN":"打敗魔王，在末日降臨之前獲得短暫的喘息機會，本次遠征的目的就充分達成了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하지만 저희의 연구가 결실을 맺게 되면… 그땐 비로소 종말의 위협에서 해방되어, 영원한 평화를 얻을 수 있겠죠.","JPN":"ですが、私たちの研究が実を結べば……私たちはついに終末の脅威から解放され、永遠の平和を享受するでしょう。","ENG":"And when our research comes to fruition... we will finally be free of the looming threat of the end and attain eternal tranquility.","TWN":"但是，如果我們的研究取得成果……我們將真正擺脫世界末日的威脅，獲得永恆的和平。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"우리의 성무는 이 세계, 엘리시온의 존속을 바라는 이들의 믿음에 부응하는 것이다.","JPN":"我々の聖務はこの世界、エリシオンの存続を望む者たちの信仰に応えることだ。","ENG":"Our sacred mission is to answer the faith of those who wish to see Elysion's continued existence.","TWN":"我們的聖務是不辜負那些希望這個艾利森世界的存續之人們的信賴。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그들의 믿음을 저버리지 마라, 네퀴티아.","JPN":"彼らの信仰を裏切るでないぞ、ネキティア。","ENG":"Do not betray their trust, Nequitia.","TWN":"不要辜負他們的信仰，莉奎蒂亞。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…물론입니다, 예하.","JPN":"……もちろんです、猊下。","ENG":"...Of course, Your Eminence.","TWN":"……當然了，主教。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"이 원정의 피날레는 우리의 승전보가 될 것이다.","JPN":"この遠征のフィナーレは我々の勝利の来報になるだろう。","ENG":"The finale of this expedition shall trumpet our victory.","TWN":"這次遠征將以我們的勝利收尾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"엘리시온의 용사들이여.","JPN":"エリシオンの勇者よ。","ENG":"Soldiers of Elysion.","TWN":"艾利森的勇士們啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"진군하라.","JPN":"進軍せよ。","ENG":"Forward.","TWN":"進軍。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 배가 많이 고팠나보네요.","JPN":"はは、とてもお腹が空いてたんですね。","ENG":"Hah hah, you must've been hungry.","TWN":"哈哈，你一定餓壞了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"먹어둬요. 험난한 세상, 굶기까지 하면 서글프니까요.","JPN":"お食べ。険しい世界で、お腹を空かしていると悲しいですから。","ENG":"Eat up. It'd be a tragedy to starve in an already cruel world.","TWN":"多吃點吧。外面的世界很艱難，填飽肚子才有力氣扛下去。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_QB","text":{"KOREA":"고양이랑은 제법 친한가 보네요.","JPN":"猫と仲がいいんですね。","ENG":"Seems like you've made good friends with the cat.","TWN":"你一定很擅長和貓打交道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어릴 적에도 이런 길고양이 한 마리가 집 주변 골목을 어슬렁거리곤 했었죠.","JPN":"小さい頃にもこんな野良猫が一匹、家の周りをうろついてたんです。","ENG":"When I was little, there used to be a stray cat like this that wandered around my neighborhood.","TWN":"在我小時候，我家附近的小巷裡就經常有這樣的流浪貓出沒。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가끔 밥을 챙겨주면서 친해졌는데, 한동안은 이상할 정도로 오랫동안 보이지 않더군요.","JPN":"たまにエサをあげて懐いてくれたんですけど、ある日を堺に見なくなりました。","ENG":"I got close to it by feeding it from time to time, and then it disappeared for a long while.","TWN":"我偶爾會給牠餵食，變得越來越親近，但很長一段時間裡卻沒有再見到牠。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러다 수 차례 계절이 지나가고 고양이를 떠올리지 않게 됐을 때쯤, 대문 앞을 꼬리 달린 검은 형체가 우두커니 지키고 있더라고요.","JPN":"それから数年後、あの猫を忘れた頃に、玄関の前で尻尾のついた黒い影が佇んでいたんです。","ENG":"Many seasons had passed when I forgot about the cat, but then I found a black figure with a tail guarding my front door.","TWN":"後來過了幾年，在我幾乎忘掉了那隻貓的存在時，有一天卻發現一個長著尾巴的黑影站在大門口。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 형체가 꼬리의 날붙이를 세워 달려들었을 때, 겁을 먹고 꼼짝 못하던 절 어머니께서 구해주셨죠.","JPN":"その影が尻尾の刃を向けて飛びかかってきた瞬間、恐怖で動けなかった僕をお母さんが助けてくれました。","ENG":"When that figure jumped at me with its sharpened tail, I got scared and froze up, and my mother came to save me.","TWN":"那個黑影的尾巴上豎起了刀刃向我襲來，還好媽媽及時趕過來救了被嚇傻的我。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"침식체를 본 건 그때가 처음이었어요.","JPN":"侵食体を見たのは、あの時が初めてでした。","ENG":"That was the first time I saw a C.O.","TWN":"那是我第一次看到侵蝕體。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무도 저에게 그것이 뭔지 설명해주지 않았지만…","JPN":"誰も僕にあれが何だったのか教えてはくれませんでしたが……","ENG":"No one explained to me what that was...","TWN":"沒有人向我解釋他是什麼，但……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예전의 그 고양이를 다시 만날 수 없을 거라는 건 알겠더군요.","JPN":"あの猫にはもう二度と、会えないということだけは理解できました。","ENG":"But I instinctively knew that I would never be able to see that cat again.","TWN":"我知道我再也見不到之前的那隻貓了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_QB","text":{"KOREA":"저런. 어린 나이에 충격이 컸겠군요.","JPN":"それは……子供にとっては、とても衝撃的な出来事でしたね。","ENG":"My, my. It must've been traumatizing for a child.","TWN":"唉，小小年紀一定受了不少打擊。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한 번 침식체가 되면, 아무리 소중한 것도 돌이킬 수 없다는 현실은 정말 지독하죠.","JPN":"一度侵食体になると、もう元には戻らない。この現実は、本当に残酷だと思います。","ENG":"Such is the cruel reality where nothing, not even your most cherished ones, cannot be reverted back from becoming a C.O.","TWN":"現實確實很殘酷，珍貴的存在一旦變成侵蝕體就再也無法挽回了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런 면에서, 최근 관리자님께선 이번에 아주 큰 성과를 거두셨어요.","JPN":"その点で、管理者さんは今回とても素晴らしい成果を出しました。","ENG":"In that sense, the Administrator recently accomplished a monumental achievement.","TWN":"在這方面，管理者最近取得了了不起的成果。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>원래대로라면 절대 돌이킬 수 없는 것을 돌이키는데 성공하셨으니까요.</color>","JPN":"<color=#ffd34c>本来なら絶対に取り返しのつかないものを、取り返すことに成功したのですから。</color>","ENG":"<color=#ffd34c>He succeeded in reverting something that should not have been possible to revert.</color>","TWN":"<color=#ffd34c>成功挽回了本不可挽回的東西。</color>"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"기적을 바라던 한 명의 인간을 초석으로, 언젠간 머지않아 세계 또한 관리자님의 뜻대로 구원받게 될 거라 기대하고 있습니다.","JPN":"奇跡を求めていた一人の人間を礎に、いつか世界もまた管理者さんの意志通り、救われることを期待しています。","ENG":"Starting with the human who wished for a miracle, I believe that the world will soon be saved following the Administrator's will.","TWN":"我相信以一位盼望奇蹟之人為基石，這個世界也會如管理者的意願得到救贖。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신 같은 사람의 입에서 그런 말이 나올 줄은 몰랐네요.","JPN":"君のような人の口から、そんな言葉が出るとは思っていませんでした。","ENG":"I never thought I'd hear those words from someone like you.","TWN":"沒想到你這樣的人也會說出這種話。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"마왕의 힘을 흡수한 영향으로 성격이 바뀌기라도 한 걸까요?","JPN":"魔王の力を吸収した影響で、性格が変わってしまったんでしょうか。","ENG":"Perhaps your personality changed after absorbing the Demon Lord's power?","TWN":"或許是我吸收的魔王之力影響到了性格？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저는 이 길에 들어선 뒤로, 단 한 번도 마음을 바꾼 적이 없습니다.","JPN":"僕はこの道に入ってから、たったの一度も意志を変えたことはありません。","ENG":"I have never changed my mind after I started taking this path.","TWN":"自從我踏上這條路，我就從未改變過自己的想法。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"단지 추구하는 방식이 관리자님과는 다르다… 정도로 이해해주면 고맙겠군요.","JPN":"ただ、追求する方法が管理者さんとは違う……とでも思ってください。","ENG":"To put it simply... the Administrator and I merely have different ways of pursuing the same thing.","TWN":"只是追求的方式與管理者稍有不同而已……希望你能理解。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오히려 그 짧은 시간에 가장 많이 변화를 겪은 건 시윤 군이라 생각해요.","JPN":"むしろ、あの短期間で一番変化したのはシリュウ君だと思いますよ。","ENG":"I would say that you are the one who went through the most change in this short amount of time.","TWN":"我覺得在如此短時間內經歷最多變化的人反而是時雲。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리자님조차 아주 오랫동안 해결하지 못했던 용혈의 시련을 시윤 군은 아주 훌륭하게 극복해냈으니까요.","JPN":"管理者さんですら長い間解決できなかった龍血の試練を、シリュウ君は見事乗り越えたんですから。","ENG":"You've brilliantly overcome the trials of Dragon Blood that even the Administrator himself couldn't solve for a very long time.","TWN":"龍血的試煉就連管理者也一直未能解決，而時雲卻很好的克服了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그날 시윤 군이 바꾼 숙명은 관리자님께 얼터니움의 가능성을 보여준 계기가 되었을 겁니다.","JPN":"あの日、シリュウ君が変えた宿命は管理者さんがオルタニウムの可能性を見出すきっかけになったはずです。","ENG":"The destiny you changed that day likely showed the Administrator the possibilities of Alternium.","TWN":"時雲在那天改變的宿命一定讓管理者看到了黑化永恆之金的潛力。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"주한 씨와 연화 씨도 분명 자랑스러워하실 거예요.","JPN":"アキヤマさんと蓮華さんもきっと誇らしいでしょうね。","ENG":"Joo Han and Yeonhwa would also be proud.","TWN":"我相信周翰和蓮華也一定會引以為豪。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하… 말씀은 감사합니다만, 별로 그쪽한테 듣고 싶은 얘긴 아니네요.","JPN":"はは……お言葉はありがたいですが、そちらの口から聞きたい話ではありませんね。","ENG":"Hah hah... I appreciate the kind words, but I'd rather not hear it coming from you.","TWN":"哈哈……謝謝你這麼說，但並不想從你口中聽到這些話。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나저나, 그런 엄청난 사고를 쳐 놓고서 고작 남의 집에서 숨는 게 다음 계획인가요?","JPN":"それより、あんな大事故を起こしておいて、人の家に隠れているのが今回の計画なんですか？","ENG":"Anyway, is your next step to hide in another person's house after causing all that trouble?","TWN":"話說你在闖了那麼大禍之後，想出的計畫只是躲到別人家裡而已嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"열심히 일한 자신에게 잠시 휴식을 주는 거죠.","JPN":"頑張った自分に、休息を与えてるんですよ。","ENG":"A temporary break for myself after having worked very hard.","TWN":"給辛勤工作的自己獎勵一段假期。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"휴가를 권할 상사도 없는 입장이라, 제 건강은 스스로 챙기는 수밖에 없거든요.","JPN":"休むよう諭してくれる上司もいないし、自分の健康は自分で管理するしかありませんから。","ENG":"I don't have a boss to offer me a vacation, so I need to take care of my own health.","TWN":"我現在沒有長官能給我安排休假，只能靠我自己照顧自己的健康。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무렇지 않은 듯이 말하지만, 역시 그 마왕의 힘이라는 게 감당하기엔 좀 버거우신 모양이네요.","JPN":"なんともないように話してますけど、やはりその魔王の力ってものが身に余っているようですね。","ENG":"You say that very casually, but it seems like the Demon Lord's power is burdening you quite a bit.","TWN":"你雖然說得若無其事，但魔王之力似乎讓你有些吃不消喔。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"부정하진 않겠어요. 익숙하지 않은 힘을 통제하려면 시간이 필요하거든요.","JPN":"否定はしません。慣れない力を統制するには時間が必要なので。","ENG":"I'll admit, it takes time to control power that's alien to me.","TWN":"我不否認，控制陌生的力量確實需要時間。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면 저에겐 좋은 기회라고 봐도 되겠죠?","JPN":"だとすれば、この状況は僕にとって絶好のチャンスと言えますね。","ENG":"That sounds like the perfect opportunity for me.","TWN":"所以這對我來說是個好機會，對嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 그렇다고 볼 수도…","JPN":"はは、そうなのかも……","ENG":"Haha, maybe it–","TWN":"哈哈，可以這麼說……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런… 기척은 못 느꼈는데. 역시 같이 계셨네요.","JPN":"おっと……気配がないと思っていましたが、やっぱり一緒でしたか。","ENG":"Well... I didn't sense you there, but I'm not surprised.","TWN":"唉……你果然也在，我沒察覺到氣息。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"까불지 말고 물러서, 아가.","JPN":"下がりなさい、坊や。","ENG":"Quit your tantrum and step back, boy.","TWN":"別逞強了，快走吧，孩子。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한 가지 오해를 정정하자면, 저는 딱히 숨어있을 생각이 없습니다.","JPN":"一応言っておきますが、僕は別に隠れているつもりはありません。","ENG":"I'd like to correct your statement by saying I never intended to hide.","TWN":"有一點你誤會了，我並沒有想躲藏。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시윤 군을 만나면 알려주고 싶은 게 있었거든요.","JPN":"シリュウ君に会ったら、教えてあげたいことがあったんですよ。","ENG":"There was something I wanted to tell you, Shiyoon.","TWN":"因為我有些話想要和時雲說。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런데, 스승님의 매서운 살기가 아직도 느껴지지 않는 걸 보면…","JPN":"ところで、師匠の鋭い殺気が未だ感じられないのを見ると……","ENG":"However, I don't sense Master's malice yet, which means...","TWN":"但是竟然還沒有感受到師父的淩厲殺氣，說明……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금은 시윤 군 혼자 뿐인 모양이네요.","JPN":"今はシリュウ君一人だけのようですね。","ENG":"You must be alone, Shiyoon.","TWN":"時雲現在是孤身一人。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님께선 더 중요한 용무가 있으셔서요.","JPN":"師匠にはもっと重要な任務がありますから。","ENG":"Master has more important matters to tend to.","TWN":"師父她還有更重要的工作。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수제자의 안위를 포기할 정도로 중요한 용무라니. 실망이 크겠어요.","JPN":"この状況で一番弟子を置いて任務とは、ガッカリしますよね。","ENG":"Matters that outweigh the safety of her best pupil? You must be disappointed.","TWN":"竟然為了工作對大弟子的安危不管不顧，你一定很失望吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 임무는 당신을 감시하는 겁니다. 그런 자질구레한 일에 스승님까지 나설 필요는 없죠.","JPN":"僕の任務は君を監視することです。こんなことに、師匠が関わる必要はありません。","ENG":"My duty is to keep an eye on you. Trivial duties like this don't require Master's attention.","TWN":"監視你的任務靠我一個人足矣，沒必要師父為這些瑣事費功夫。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 보호자 보살핌을 받을 나이는 이미 지나서요.","JPN":"もう、保護者に守られるような年でもありませんからね。","ENG":"Plus, I'm far too old to be babysat.","TWN":"而且我已經過了需要監護的年齡。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"흐음… 이거 골치 아프게 됐군요.","JPN":"ふむ……それは困りましたね。","ENG":"Hmm... That's a little troublesome.","TWN":"唉……這下可頭疼了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아무래도, 스승님은 본인이 맡겨 둔 힘을 되찾으러 가신 모양이네요.","JPN":"どうやら、師匠はご自分が預けた力を取り戻しに行かれたようです。","ENG":"Master must've gone to reclaim the power she put away.","TWN":"師父顯然是去收回她託付的力量了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"정보에 밝은 그녀라면 분명 이 타이밍을 노리고 움직인 거겠죠.","JPN":"情報に精通している彼女ですから、きっとこのタイミングを狙って動いたのでしょう。","ENG":"And our well-informed star knew that and picked the right time to act.","TWN":"消息靈通的她一定是利用了這個時機。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용건을 잘 모르겠는데.","JPN":"どんな用件なのかは知り得ませんが。","ENG":"I'm not sure what you're getting at.","TWN":"我聽不明白。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대체 무슨 말이 하고 싶으신 거죠?","JPN":"何が言いたいんです？","ENG":"So, what's your point?","TWN":"你到底想說什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"원한다면 거두절미하고 핵심을 말하죠.","JPN":"お望みであれば、要点だけでも話してあげましょう。","ENG":"I'll cut to the chase.","TWN":"那我就開門見山了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금 저희 내부에서 배반이 벌어지고 있습니다.","JPN":"今、僕たちの内部で裏切りが起きています。","ENG":"There's a traitor within our ranks.","TWN":"我們內部目前發生了叛變。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};